#include "stm32f10x.h"
#include<stdbool.h>

#define bits 7
#define prescaler 16
#define pinNo 9	

uint8_t message[]="print. ";
uint16_t tData, tdCount, tcCount;
bool txBusy=0;//either 1 or 0

void PwrRccInit(void);
void GPIOInit(void);
void gpioIntInit(void);
void square(void);
void send7(uint16_t a);
void puts(uint8_t* a);

int main(){

	uint32_t a;

	PwrRccInit();
	GPIOInit();
	gpioIntInit();

	GPIOB->ODR = 0x0004;

	while(1){
//		send7('m');
		puts(message);
		for(a=0; a<200000; a++);
		}
	}

void send7(uint16_t a){
	tData = (a<<1) | (1<<(bits+1));
	tdCount=0;//tedad bit ha ra mishomarad
	tcCount=prescaler-1;// 16 ta mishmarad
//	EXTI->IMR = 1<<pinNo;
	txBusy = 1;//mashghoul ferestdan
	}

void puts(uint8_t* a){
	while(*a){
		while(txBusy==1);
		send7(*(a++));
		}
	}

void PwrRccInit(void){
	PWR->CR  = 0x00000000;
	PWR->CSR = 0x00000000;

	RCC->CR   =   0x00000083;
	RCC->CFGR =   0x00000000;
	RCC->CIR  =   0x00000000;
	}

void GPIOInit(void){
	RCC->APB2ENR   =   0x0000000c ;
	RCC->APB2RSTR |=   0x0000000c ;
	RCC->APB2RSTR &= ~(0x0000000c);
	GPIOA->CRL     =   0x22222222 ;
	GPIOA->CRH     =   0x44444444 ;
	GPIOB->CRL     =   0x44442222 ;
	GPIOB->CRH     =   0x44444444 ;
	}

void gpioIntInit(void){	//GPIO pin Interrrupt
	RCC->APB2ENR|=0x0001;
	AFIO->EXTICR[2]=0x0010;	//interrupt from port B pin 9
	EXTI->IMR   = 1<<pinNo;		//bit to generate interrup is defined by pinNo
	EXTI->EMR   = 0<<pinNo;			//no event
	EXTI->RTSR  = 0<<pinNo;	//rising edge(no)
	EXTI->FTSR  = 1<<pinNo;			//falling edge interrupt
	EXTI->PR    = 1<<pinNo;				//clear pending interrupts
	EXTI->SWIER = 0<<pinNo;		//no software interrupt
	NVIC_EnableIRQ(EXTI9_5_IRQn);
	}

void EXTI9_5_IRQHandler(void){
	EXTI->PR = 1<<pinNo;				//clear pending interrupts
	if(txBusy==1){
		if((++tcCount)>=prescaler){
			if((tdCount)<(bits+2)){
				if((tData & (1<<tdCount))==(1<<tdCount))
					GPIOB->ODR |= 0x0004;
				else
					GPIOB->ODR &= ~(0x0004);
				tdCount++;
				}
			else{
//				EXTI->IMR = 0;
				txBusy = 0;
				}
			tcCount=0;
			}
		}
	}
